app.get('/users', authenticateToken, (req, res) => { ... });
```

#### 3. No Security Headers (OWASP A05 – Security Misconfiguration)
Express does not set security-relevant HTTP headers by default. This leaves the app exposed to clickjacking, MIME-sniffing, and other header-based attacks.

```js
// ✅ Use helmet (npm install helmet)
const helmet = require('helmet');
app.use(helmet());
// Adds: X-Content-Type-Options, X-Frame-Options, HSTS,
//       Content-Security-Policy, Referrer-Policy, and more
```

#### 4. No Rate Limiting (OWASP A04 – Insecure Design)
Endpoints accept unlimited requests with no throttling, making the app trivially vulnerable to brute-force, enumeration, and DoS attacks.

```js
// ✅ Use express-rate-limit (npm install express-rate-limit)
const rateLimit = require('express-rate-limit');
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,                  // limit each IP to 100 requests per window
  standardHeaders: true,
  legacyHeaders: false,
});
app.use(limiter);
```

